import{_ as s,o as a,c as t,as as i}from"./chunks/framework.Cz19ueXu.js";const u=JSON.parse('{"title":"Design Tokens","description":"","frontmatter":{},"headers":[],"relativePath":"guide/design-tokens.md","filePath":"guide/design-tokens.md","lastUpdated":1777237423000}'),n={name:"guide/design-tokens.md"};function o(d,e,r,l,c,p){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="design-tokens" tabindex="-1">Design Tokens <a class="header-anchor" href="#design-tokens" aria-label="Permalink to &quot;Design Tokens&quot;">​</a></h1><p><code>@vuecs/design</code> is the CSS-variable layer beneath the theme system. Themes resolve <strong>class strings</strong>; design tokens define <strong>what those classes paint with</strong>.</p><h2 id="why-a-separate-layer" tabindex="-1">Why a separate layer? <a class="header-anchor" href="#why-a-separate-layer" aria-label="Permalink to &quot;Why a separate layer?&quot;">​</a></h2><p>CSS classes can change at build time — but recoloring an entire app at runtime by swapping classes means re-rendering every component, plus hoping every consumer wrote their custom CSS to match. CSS variables are read at browser paint time, so swapping their values re-tints everything live, including consumer-authored rules and dynamic SVG <code>fill=&quot;currentColor&quot;</code> icons.</p><p>That&#39;s why vuecs has both: themes pick the class names, tokens pick the colors.</p><h2 id="the-token-chain-top-to-bottom" tabindex="-1">The token chain (top to bottom) <a class="header-anchor" href="#the-token-chain-top-to-bottom" aria-label="Permalink to &quot;The token chain (top to bottom)&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. bg-primary-600          ← Tailwind v4 utility class</span></span>
<span class="line"><span>2. --color-primary-600     ← @theme mapping in @vuecs/design</span></span>
<span class="line"><span>3. --vc-color-primary-600  ← semantic-scale var (overridden by setPalette)</span></span>
<span class="line"><span>4. --color-blue-600        ← Tailwind&#39;s built-in palette</span></span>
<span class="line"><span>5. concrete hex            ← shipped by Tailwind</span></span></code></pre></div><p><code>setPalette({ primary: &#39;green&#39; })</code> rewrites layer 3 to point at <code>var(--color-green-600)</code>. Layers 1, 2, 4, 5 are untouched, so the rewrite is local and atomic.</p><h2 id="semantic-scales" tabindex="-1">Semantic scales <a class="header-anchor" href="#semantic-scales" aria-label="Permalink to &quot;Semantic scales&quot;">​</a></h2><p>Six scales, each with shades 50–950:</p><table tabindex="0"><thead><tr><th>Scale</th><th>Default palette</th><th>Usage</th></tr></thead><tbody><tr><td><code>primary</code></td><td><code>blue</code></td><td>Brand color, primary CTAs</td></tr><tr><td><code>neutral</code></td><td><code>neutral</code></td><td>Backgrounds, borders, text</td></tr><tr><td><code>success</code></td><td><code>green</code></td><td>Success states, valid inputs</td></tr><tr><td><code>warning</code></td><td><code>amber</code></td><td>Warnings, caution</td></tr><tr><td><code>error</code></td><td><code>red</code></td><td>Errors, destructive actions</td></tr><tr><td><code>info</code></td><td><code>sky</code></td><td>Informational, links</td></tr></tbody></table><p>Override defaults at runtime with <code>setPalette({ primary: &#39;green&#39;, neutral: &#39;zinc&#39; })</code>.</p><h2 id="semantic-aliases" tabindex="-1">Semantic aliases <a class="header-anchor" href="#semantic-aliases" aria-label="Permalink to &quot;Semantic aliases&quot;">​</a></h2><p>These flip under <code>.dark</code>:</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--vc-color-bg            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* page/card background */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--vc-color-bg-muted      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* slightly recessed */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--vc-color-bg-elevated   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* slightly raised */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--vc-color-fg            </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* primary text */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--vc-color-fg-muted      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* secondary text */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--vc-color-border        </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* default border */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--vc-color-border-muted  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* subtle border */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--vc-color-ring          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* focus ring */</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--vc-color-on-primary    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* foreground on filled primary bg */</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--vc-color-on-success    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* etc. */</span></span></code></pre></div><p>In Tailwind utilities: <code>bg-bg</code>, <code>text-fg</code>, <code>border-border</code>, <code>ring-ring</code>, <code>text-on-primary</code>. These are exposed via the <code>@theme</code> block in <code>@vuecs/design</code>.</p><h2 id="radius" tabindex="-1">Radius <a class="header-anchor" href="#radius" aria-label="Permalink to &quot;Radius&quot;">​</a></h2><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--vc-radius-sm:   0.125rem;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--vc-radius-md:   0.375rem;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--vc-radius-lg:   0.5rem;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--vc-radius-xl:   0.75rem;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--vc-radius-full: 9999px;</span></span></code></pre></div><p>Available as Tailwind utilities <code>rounded-sm</code>, <code>rounded-md</code>, <code>rounded-lg</code>, <code>rounded-xl</code>, <code>rounded-full</code>.</p><h2 id="runtime-palette-switching" tabindex="-1">Runtime palette switching <a class="header-anchor" href="#runtime-palette-switching" aria-label="Permalink to &quot;Runtime palette switching&quot;">​</a></h2><div class="language-ts vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { setPalette } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;@vuecs/design&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">setPalette</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">({ primary: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;green&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, neutral: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;zinc&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> });</span></span></code></pre></div><p>Inserts or updates a <code>&lt;style id=&quot;vc-palette&quot;&gt;</code> element in <code>&lt;head&gt;</code>. Idempotent — calling it again replaces the previous block.</p><p>For SSR (Nuxt), use <code>renderPaletteStyles(palette)</code> — pure function returning a CSS string. The Nuxt module emits this into the head before first paint.</p><h2 id="circular-reference-caveat" tabindex="-1">Circular reference caveat <a class="header-anchor" href="#circular-reference-caveat" aria-label="Permalink to &quot;Circular reference caveat&quot;">​</a></h2><p>Tailwind utilities like <code>bg-neutral-500</code> use <strong>Tailwind&#39;s</strong> default <code>--color-neutral-*</code> palette, <strong>not</strong> the vuecs <code>--vc-color-neutral-*</code> palette. This is intentional: rebinding <code>--color-neutral-*</code> to <code>var(--vc-color-neutral-*)</code> would create a circular reference (since <code>--vc-color-neutral-*</code> is bound to <code>var(--color-neutral-*)</code> to follow Tailwind&#39;s neutral by default), invalidating the entire chain.</p><p><strong>Practical implication:</strong> use <code>bg-bg</code>, <code>text-fg</code>, <code>border-border</code> (semantic aliases — they DO follow <code>setPalette({ neutral: ... })</code>) instead of <code>bg-neutral-100</code>, <code>text-neutral-900</code>, <code>border-neutral-200</code> (raw Tailwind, doesn&#39;t follow palette).</p><h2 id="bootstrap-bridges" tabindex="-1">Bootstrap bridges <a class="header-anchor" href="#bootstrap-bridges" aria-label="Permalink to &quot;Bootstrap bridges&quot;">​</a></h2><p>For Bootstrap consumers, <code>@vuecs/theme-bootstrap-v5</code> ships a design-token bridge (<code>assets/index.css</code>) that maps <code>--bs-*</code> theme vars onto <code>--vc-color-*</code>:</p><div class="language-css vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">css</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">@import</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;@vuecs/theme-bootstrap-v5&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">/* via the \`style\` conditional export */</span></span></code></pre></div><p>Bootstrap 5 components read <code>--bs-*</code> at runtime, so the bridge propagates <code>setPalette()</code> to Bootstrap components. Bootstrap 4&#39;s bridge is shipped for API parity but has limited reach — Bootstrap 4&#39;s component CSS is Sass-compiled to literal hex, so the bridge only affects consumer-authored rules.</p><h2 id="pure-ssr-safe-apis" tabindex="-1">Pure / SSR-safe APIs <a class="header-anchor" href="#pure-ssr-safe-apis" aria-label="Permalink to &quot;Pure / SSR-safe APIs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Export</th><th>Pure</th><th>Notes</th></tr></thead><tbody><tr><td><code>renderPaletteStyles(palette)</code></td><td>✅</td><td>Returns <code>:root { ... }</code> block as a string</td></tr><tr><td><code>setPalette(palette, doc?)</code></td><td>❌</td><td>DOM-only; idempotent</td></tr><tr><td><code>PaletteConfig</code></td><td>type</td><td><code>Partial&lt;Record&lt;SemanticScaleName, TailwindPaletteName&gt;&gt;</code></td></tr><tr><td><code>SEMANTIC_SCALES</code></td><td>const</td><td>Array of the 6 scale names</td></tr><tr><td><code>TAILWIND_PALETTES</code></td><td>const</td><td>Array of all 22 Tailwind palette names</td></tr></tbody></table><h2 id="vue-composables" tabindex="-1">Vue composables <a class="header-anchor" href="#vue-composables" aria-label="Permalink to &quot;Vue composables&quot;">​</a></h2><p><code>@vuecs/design</code> ships <code>usePalette()</code> and <code>useColorMode()</code> for reactive runtime palette / dark-mode state — see the dedicated <a href="/guide/composables">Composables</a> page for API reference and persistence details.</p><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/getting-started/dark-mode">Dark Mode</a> — <code>.dark</code> flip mechanics</li><li><a href="/guide/theme-system">Theme System</a> — what consumes the tokens</li><li><a href="/nuxt/">Nuxt module</a> — SSR-safe palette switching</li></ul>`,36)])])}const k=s(n,[["render",o]]);export{u as __pageData,k as default};
